function HeroIconNew:ApplyIconUI()
    BaseIconNew.ApplyIconUI(self)

    self:SetIcon(self._displayShowIcon)
    self:SetIconBg(self._displayShowIconBg)

    self:UpdateStarUI()
    self:UpdateTypeImage()

    if self._showStatus then
        self:ApplyStatusImg()
    end

    if not self._isInitLockImg and self._bShowLock then
        self:InitLockImg()
    end

    self:SetStarListVisible(self._bShowStarList)
    self:SetGouTransVisible(self._showGou)
    self:SetLockTransVisible(self._bShowLock)
    self:SetShowShiftImgVisible(self._showShiftImg)
    self:SetSacrificeImgTransVisible(self._bShowSacrifice)
    self:UpdateMaskVisible()
    self:ApplyLvTxt()
    self:SetLvUIVisible(not self._noShowLv)

    self:UpdateSignStatus()
    self:UpdateLinkStatus()

    self:ShowName()
    self:ShowEndTime()
    self:ShowLimitTxt()

    self:SetShowMainFormationVisible(self._showMainFormation)

    self:RefreshTireValue()

    self:LngVersionRefresh()
    self:SetLightTransVisible(self._showLight)
end

function HeroIconNew:LngVersionRefresh()
    if not CS.IsValidObject(self._iconInst) then
        return
    end
    local tagPath = "public_txt_14_1"
    local tran = CS.FindTrans(self._iconInst, "SacrificeImg")
    self:SetCommonImg(tran, tagPath)

    if self._uiSignStatusTrans then
        local tagPath1 = "starHero_icon_txt_3"
        self:SetCommonImg(self._uiSignStatusTrans, tagPath1)
    end
end

function HeroIconNew:OnInitTrans()
    local iconInst = self._iconInst
    self._uiTypeTrans = CS.FindTrans(iconInst, "TypeImg")
    self._uiAwakenTrans = CS.FindTrans(iconInst, "AwakenImg")
    self._uiMaskLv = CS.FindTrans(iconInst, "MaskLv")
    self._uiLvTxtTrans = CS.FindTrans(iconInst, "LvTxt")

    self._uiStarTrans = CS.FindTrans(iconInst, "StarList")

    self._uiHightStarTrans = CS.FindTrans(iconInst, "HightStar")
    self._uiHightStarText = CS.FindTrans(self._uiHightStarTrans, "HightStarText")

    self._uiMaskTrans = CS.FindTrans(iconInst, "MaskImg")
    self._uiGouTrans = CS.FindTrans(iconInst, "GouImg")
    self._uiLockTrans = CS.FindTrans(iconInst, "LockImg")
    self._uiShiftImgTrans = CS.FindTrans(iconInst, "ShiftImg")
    self._uiSacrificeImgTrans = CS.FindTrans(iconInst, "SacrificeImg")
    self._nameTran = CS.FindTrans(iconInst, "nameBg/name")
    self._endTimeTrans = CS.FindTrans(iconInst, "timeBg/endTime")

    self._uiLimitTrans = CS.FindTrans(iconInst, "LimitBg/Limit")

    self._uiSignStatusTrans = CS.FindTrans(iconInst, "SignStatus")
    self._uiLinkStatusTrans = CS.FindTrans(iconInst, "LinkStatus")

    self._tireBgTran = CS.FindTrans(iconInst, "tire")
    self._tireValueTran = CS.FindTrans(iconInst, "tire/value")

    --觉醒技能点标识
    self._uiAwakenSkillTransList = {}
    for i = 1, self._uiAwakenTrans.childCount do
        local trans = CS.FindTrans(self._uiAwakenTrans, "AwakenSkill" .. i)
        local data = {
            trans = trans,
            activeTrans = CS.FindTrans(trans, "AwakenSkillActive"),
        }
        self._uiAwakenSkillTransList[i] = data
    end

    self:InitStartList()

    self._uiMainFormationIconTrans = CS.FindTrans(iconInst, "MainFormationIcon")

    self._uiLightImgTrans = CS.FindTrans(iconInst, "LightImg")
end
