function HeroIconNew:InitInfo()
    local star = 1
    local lv = 1
    local typeId = 1
    local isResonance = 0
    local form = self._form or gModelHero:GetHeroForm(self._id)

    local dataType = self._dataType
    local refId = self._refId
    local heroRef
    local monRef, monsterAddCostRef
    local skin
    local treeInfo
    local endTime
    local isTry
    if dataType == HeroIconNew.DATA_TYPE_SET then
        star = self._star
        lv = self._lv
        isResonance = self._isResonance
        skin = self._skin
        if self._isMon then
            if self._monsterAddCost then
                local costRef = self:GetMonsterAttrCostRef(self._monsterAddCost)
                if costRef then
                    star = costRef.starLv
                end
                monsterAddCostRef = costRef
            end
            local ref = self:GetMonsterAttrRef(refId)
            monRef = ref
            if not ref then
                LogError("怪物配置表里没有找到ID：" .. refId)
                typeId = 1
            else
                typeId = ref.raceType
            end
        else
            heroRef = self:GetHeroRef(refId)
            if heroRef then
                typeId = heroRef.raceType
            else
                LogError("英雄配置表里没有找到ID：" .. refId)
            end
        end
    elseif dataType == HeroIconNew.DATA_TYPE_PLAYER then
        local data = gModelHero:GetHeroById(self._id)
        if data then
            isResonance = data:GetResonanceStatus()
            star = data:GetStar()
            lv = data:GetLv()
            skin = data:GetSkin()
            refId = data:GetRefId()
            treeInfo = data:GetTreeInfo()
            endTime = data:GetEndTime()
            isTry = data:IsTryHero()
            heroRef = self:GetHeroRef(refId)
            if heroRef then
                typeId = heroRef.raceType
            else
                LogError("英雄配置表里没有找到ID：" .. refId)
            end
            self._star = star
        end
    elseif dataType == HeroIconNew.DATA_TYPE_CONF then
        heroRef = self:GetHeroRef(refId)
        if heroRef then
            if self._star and self._star > 0 then
                star = self._star
            else
                star = heroRef.initStar
            end
            lv = 1
            typeId = heroRef.raceType
        else
            LogError("配置表里没有找到英雄refID：" .. refId)
            star = 4
            lv = 1
            typeId = 1
        end
    elseif dataType == HeroIconNew.DATA_TYPE_RACE then
        star = self._star
        typeId = self._race
    elseif dataType == HeroIconNew.DATA_ONLY_SHOW then
        lv = self._lv
    end

    lv = lv or 1
    local lvStr = "" .. lv

    if self._bUpLvFunc then
        star = self._upLvFunStar
        lvStr = (self._upLvFunNum or 0) .. "/" .. self._upLvFunNeedNum
        if self._upLvFunRace ~= -1 then
            typeId = self._upLvFunRace
        end
    end

    local raceRef = self:GetHeroRaceRef(typeId)
    local raceIcon = nil
    if raceRef then
        raceIcon = raceRef.icon
    end

    self._displayStar = star
    self._lvTxtStr = lvStr
    self._displayTypeIcon = raceIcon
    self._displayResonance = isResonance
    self._awakenTreeInfo = treeInfo ~= nil and treeInfo or self._awakenTreeInfo
    self._endTime = endTime ~= nil and endTime or self._endTime
    if isTry ~= nil then
        self._isTry = isTry
    end

    local iconPath = nil
    local iconBgPath = nil

    local itemName = nil
    local itemColor = nil
    local strTypeName = ""
    if heroRef then


        local starRef = gModelHero:GetHeroStarRef(heroRef.refId, form, star)
        local effectShowId
        local quality = heroRef.quality
        -- if gModelHero:CheckIsShowHeroQualityForeign() then
        -- 	quality = heroRef.quality
        -- else
        -- 	if starRef then
        -- 		quality = starRef.quality
        -- 	end
        -- end

        if quality then
            local qualityRef = self:GetItemQualityRef(quality)
            if qualityRef then
                iconBgPath = qualityRef.iconBg
                local color = qualityRef.nameColor
                if color then
                    itemColor = LUtil.ColorByHex(color)
                end
            end

            if starRef then
                effectShowId = starRef.effectId
            end
        end

        --皮肤展示
        if skin and skin > 0 then
            effectShowId = skin
        end

        local effectRef = self:GetHeroEffectRef(effectShowId)
        if effectRef then
            iconPath = effectRef.icon
            itemName = ccLngText(effectRef.name)
        end

        local typeRef = gModelHero:GetCareerRefByRefId(heroRef.careerType)
        if typeRef then
            strTypeName = ccLngText(typeRef.name)
        end

    elseif monRef then
        local quality = self._quality   --覆盖品质字段
        if not quality then
            quality = monRef.quality
        end

        if monsterAddCostRef then
            quality = monsterAddCostRef.quality
        end
        itemName = ccLngText(monRef.name)

        local qualityRef = self:GetItemQualityRef(quality)
        if qualityRef then
            iconBgPath = qualityRef.iconBg
            local color = qualityRef.nameColor
            if color then
                itemColor = LUtil.ColorByHex(color)
            end
        end

        local effectShowId = monRef.effectId
        local effectRef = self:GetHeroEffectRef(effectShowId)
        if effectRef then
            iconPath = effectRef.icon
        end
    end

    if self._bUpLvFunc then
        if self._upLvFunRace ~= -1 or not iconBgPath then
            local qualityRef = self:GetItemQualityRefByStarLv(star)
            if qualityRef then
                iconBgPath = qualityRef.iconBg
            end
        end

        if not iconPath then
            --printInfoNR("打印而已，莫慌 ==== 升星材料选择：没有找到对应的头像，使用默认"..self._id)
            iconPath = "icon_hero_0001"
        end
    end

    self._displayShowIcon = iconPath
    self._displayShowIconBg = iconBgPath
    --self._displayShowIcon = iconPath
    --self._displayShowIconBg = iconBgPath


    if string.isempty(itemName) then
        --为空的情况是在图鉴里找角色--使用monRef的name
        if monRef then
            local effectShowId = monRef.effectId
            local effectRef = self:GetHeroEffectRef(effectShowId)


            if effectRef then
                itemName = ccLngText(effectRef.name)
            end
        end
    end

    self._displayName = itemName
    self._typeName = strTypeName



    self._displayColor = itemColor

end

function HeroIconNew:InitOnlyShowInfo()

end

function HeroIconNew:GetNameData()
    return self._displayName, self._displayColor
