------------------------------------------------------------------
function HeroIconNew:UpdateTypeImage()
    local typeImg = self._displayTypeIcon
    if not string.isempty(typeImg) then
        self:SetCommonImg(self._uiTypeTrans, typeImg)
        if not self._uiTypeTrans.gameObject.activeSelf then
            CS.ShowObject(self._uiTypeTrans, true)
        end

        --觉醒技能点标识显示
        self:UpdateAwakenImage()
    else
        if self._uiTypeTrans.gameObject.activeSelf then
            CS.ShowObject(self._uiTypeTrans, false)
        end
    end
end

------------------------------------------------------------------
function HeroIconNew:UpdateAwakenImage()
    local star = self._star
    local heroAwaken = GameTable.CharacterConfigRef["heroAwaken"]
    local awakenTreeInfo = self._awakenTreeInfo
    local isShow = awakenTreeInfo and awakenTreeInfo:IsAwakenActivate() and (star >= heroAwaken)
    if isShow then
        if self._hideTree then
            CS.ShowObject(self._uiAwakenTrans, false)
        else
            if not self._uiAwakenTrans.gameObject.activeSelf then
                CS.ShowObject(self._uiAwakenTrans, true)
            end
            local lv = awakenTreeInfo:GetAwakenAllLv()
            local iconPath = gModelHero:GetAwakenIconPathByLvl(lv, false)
            if LxUiHelper.IsImgPathValid(iconPath) then
                self:SetCommonImg(self._uiAwakenTrans, iconPath)
            else
                CS.ShowObject(self._uiAwakenTrans, false)
            end
        end

        --self:UpdateAwakenSkillsTrans()
    else
        if self._uiAwakenTrans.gameObject.activeSelf then
            CS.ShowObject(self._uiAwakenTrans, false)
        end
    end
end

function HeroIconNew:UpdateAwakenSkillsTrans()
    local treeInfo = self._awakenTreeInfo
    local skillNum = treeInfo and treeInfo:GetAwakenSkillNum() or 0
    for k, v in ipairs(self._uiAwakenSkillTransList) do
        local isShow = k <= skillNum
        local activeTrans = v.trans
        if isShow then
            if not activeTrans.gameObject.activeSelf then
                CS.ShowObject(activeTrans, true)
            end
        else
            if activeTrans.gameObject.activeSelf then
                CS.ShowObject(activeTrans, false)
            end
        end
    end
end

