function HeroIconNew:DoNotShowLv(b)
    if self._noShowLv == b then
        return
    end
    self._noShowLv = b
    if not self:IsIconValid() then
        return
    end
    self:SetLvUIVisible(not b)
end

function HeroIconNew:SetLvUIVisible(b)
    if self._uiLvTxtTrans and self._uiLvTxtTrans.gameObject.activeSelf ~= b then
        CS.ShowObject(self._uiLvTxtTrans, b)
    end
    local showMaskLv = b
    if self._showLvMask ~= -1 then
        showMaskLv = self._showLvMask == 1
    end
    --[[	if self._uiMaskLv and self._uiMaskLv.gameObject.activeSelf ~= showMaskLv then
            CS.ShowObject(self._uiMaskLv,showMaskLv)
        end]]
end
