    self._showLimitTxt = not string.isempty(str)
end

function HeroIconNew:ShowLimitTxt()
    if not CS.IsValidObject(self._uiLimitTrans) then
        return
    end
    CS.ShowObject(self._uiLimitTrans.parent, self._showLimitTxt)
    if not self._showLimitTxt then
        return
    end

    local size
    if gLGameLanguage:IsForeignVersion() then
        size = 16
    end
    self:SetXUIText(self._uiLimitTrans, self._limitTxt, size)
end
