function HeroIconNew:ShowSacrificeImg(b)
    if b == nil then
        b = gModelHero:GetAutoSacrificeStatus() and self._displayStar <= ModelCallHero.SACRIFICE_SEL_STAR
    end

    if self._bShowSacrifice == b then
        return
    end
    self._bShowSacrifice = b
    if not self:IsIconValid() then
        return
    end
    self:SetSacrificeImgTransVisible(b)
    self:UpdateMaskVisible()
end

function HeroIconNew:SetSacrificeImgTransVisible(bVisible)
    bVisible = bVisible and bVisible or false
    local gameObj = self._uiSacrificeImgTrans.gameObject
    if gameObj.activeSelf ~= bVisible then
        CS.ShowObject(gameObj, bVisible)
        if bVisible then
            self:SetCommonImg(self._uiSacrificeImgTrans, "public_txt_14_1")
        end
    end
end
-----------------------------------------------------------------
function HeroIconNew:ShowGouImg(b)
    if self._showGou == b then
        return
    end
    self._showGou = b

    if not self:IsIconValid() then
        return
    end

    self:SetGouTransVisible(self._showGou)
    self:UpdateMaskVisible()
end

function HeroIconNew:ShowLock(bLock)
    bLock = bLock or false and true

    if self._bShowLock == bLock then
        return
    end
    self._bShowLock = bLock

    if not self:IsIconValid() then
        return
    end
    if not self._isInitLockImg then
        self:InitLockImg()
    end
    self:SetLockTransVisible(self._bShowLock)
    self:UpdateMaskVisible()
end

-----------------------------------------------------------------
function HeroIconNew:ShowStatusImg(b, ignoreResonance)
    self._showStatus = b
    if ignoreResonance == nil then
        ignoreResonance = false
    end
    self._ignoreResonance = ignoreResonance
    if not self:IsIconValid() then
        return
    end
    self:ApplyStatusImg()
    self:SetLockTransVisible(self._bShowLock)
    self:UpdateMaskVisible()
end

function HeroIconNew:ApplyStatusImg()
    if not self._showStatus then
        return
    end
    local ignoreResonance = self._ignoreResonance
    local serverData = gModelHero and gModelHero:GetHeroServerDataById(self._id) or nil
    if serverData then
        local lock, isCombat, isResonance = serverData.lock, serverData.isCombat, serverData.isResonance
        local imgPath = nil
        local bShowLock = false
        if isCombat == 1 then
            imgPath = "heropalace_icon_1"
            bShowLock = true
        elseif lock == 1 then
            imgPath = "public_lock_1"
            bShowLock = true
        elseif isResonance == 1 and not ignoreResonance then
            imgPath = "heropalace_icon_2"
            bShowLock = true
        end
        if imgPath then
            self:InitLockImg(imgPath)
        end
        self._bShowLock = bShowLock
    else
        self._bShowLock = false
    end
end

function HeroIconNew:InitLockImg(imgPath)
    imgPath = imgPath or "public_lock_1"
    self._isInitLockImg = true
    self:SetCommonImg(self._uiLockTrans, imgPath)
end

function HeroIconNew:SetLockTransVisible(bVisible)
    bVisible = bVisible and bVisible or false
    local gameObj = self._uiLockTrans.gameObject
    if gameObj.activeSelf ~= bVisible then
        CS.ShowObject(gameObj, bVisible)
    end
end

function HeroIconNew:SetGouTransVisible(bVisible)
    bVisible = bVisible and bVisible or false
    local gameObj = self._uiGouTrans.gameObject
    if gameObj.activeSelf ~= bVisible then
        CS.ShowObject(gameObj, bVisible)
    end
end

function HeroIconNew:SetStarListVisible(bVisible)
    if bVisible == nil then
        bVisible = true
    end
    local gameObj = self._uiStarTrans.gameObject
    if gameObj.activeSelf ~= bVisible then
        CS.ShowObject(gameObj, bVisible)
    end
end

function HeroIconNew:UpdateMaskVisible()
    local bVisible = self._bShowLock or self._showGou or self._bShowMaskOnly or self._bShowSacrifice
    local uiMaskTrans = self._uiMaskTrans
    if not uiMaskTrans then
        return
    end
    local gameObj = uiMaskTrans.gameObject
    if gameObj.activeSelf ~= bVisible then
        CS.ShowObject(gameObj, bVisible)
    end
end

function HeroIconNew:SetShowNameStatus(show)
    self._showName = show
    self:ShowName()
end

function HeroIconNew:ShowName()
    if not CS.IsValidObject(self._nameTran) then
        return
    end
    CS.ShowObject(self._nameTran.parent, self._showName)
    if not self._showName then
        return
    end

    local flag = LGameLanguage:GetLanguageFlag()
    local size
    if flag ~= "zhcn" then
        size = 20
    end

    if self._showType then
        size = 24
        self:SetXUIText(self._nameTran, self._typeName, size)
    else
        self:SetXUIText(self._nameTran, self._displayName, size)
    end
end

function HeroIconNew:ShowEndTime()
    if not CS.IsValidObject(self._endTimeTrans) then
        return
    end

    local isShow = not self._showName and self._isTry
    CS.ShowObject(self._endTimeTrans.parent, isShow)
    local endTimeKey = "_endTimeKey"
    if not isShow then
        self:TimerStop(endTimeKey)
        return
    end

    ----- cxl:链接状态直接显示，倒计时盖住就盖住，其他地方可以看倒计时
    --[[	if self._showSignStatus then
            self:TimerStop(endTimeKey)
            self:TryHeroSignStatus()
            return
        end
        if self._showLinkStatus then
            self:TimerStop(endTimeKey)
            self:TryHeroLinkStatus()
            return
        end]]

    self._endTimeKey = endTimeKey
    local timeValue = self._endTime - GetTimestamp()
    if timeValue > 0 then
        self:RefreshHeroEndTimeText()
        self:TimerStart(endTimeKey, 1, false, timeValue + 1)
    else
        self:TimerStop(endTimeKey)
    end
end

function HeroIconNew:RefreshHeroEndTimeText()
    if not self._endTime then
        self:TimerStop(self._endTimeKey)
        return
    end
    local timeValue = self._endTime - GetTimestamp()
    if timeValue <= 0 or not CS.IsValidObject(self._endTimeTrans) then
        self:TimerStop(self._endTimeKey)
        return
    end

    local str = LUtil.FormatTimespanToMin2(timeValue)
    self:SetXUIText(self._endTimeTrans, str)
end

function HeroIconNew:OnTimer(key)
    if key == self._endTimeKey then
        self:RefreshHeroEndTimeText()
    end
end

function HeroIconNew:TryHeroSignStatus()
    if not CS.IsValidObject(self._endTimeTrans) then
        return
    end
    CS.ShowObject(self._uiSignStatusTrans, false)
    local parentTrans = self._endTimeTrans.parent
    if not parentTrans.gameObject.activeSelf then
        CS.ShowObject(self._endTimeTrans.parent, true)
    end
    self:SetXUIText(self._endTimeTrans, ccClientText(31224))
end

function HeroIconNew:TryHeroLinkStatus()
    if not CS.IsValidObject(self._endTimeTrans) then
        return
    end
    CS.ShowObject(self._uiLinkStatusTrans, false)
    local parentTrans = self._endTimeTrans.parent
    if not parentTrans.gameObject.activeSelf then
        CS.ShowObject(self._endTimeTrans.parent, true)
    end
    self:SetXUIText(self._endTimeTrans, ccClientText(31225))
end

function HeroIconNew:RefreshTireValue()
    if not CS.IsValidObject(self._tireBgTran) then
        return
    end
    CS.ShowObject(self._tireBgTran, self._showTire)
    if not self._showTire then
        return
    end

    if self._isMon then
        return
    end

    -- 【G公共支持】删除暗黑战争相关数据
    -- local value = gModelDarkWar:GetTireValue(self._refId)
    self:SetXUIText(self._tireValueTran, value)
end

